<?php
require_once __DIR__.'/config/auth.php'; if(current_user()){header('Location: dashboard.php');exit;} $error='';
if($_SERVER['REQUEST_METHOD']==='POST'){ $username=trim($_POST['username']??'');$email=trim($_POST['email']??'');$password=$_POST['password']??''; if(!$username||!$email||!$password)$error='Fill all fields.'; else { $stmt=db()->prepare('INSERT INTO users (username,email,password_hash) VALUES (?,?,?)'); $hash=password_hash($password,PASSWORD_DEFAULT); $stmt->bind_param('sss',$username,$email,$hash); if(!$stmt->execute())$error='Username or email already exists.'; else {$_SESSION['user']=['id'=>$stmt->insert_id,'username'=>$username,'email'=>$email];header('Location: dashboard.php');exit;}}}
require_once __DIR__.'/header.php'; ?>
<div class="panel auth"><h2>Create your Link-Locker account</h2><p class="muted">Start saving useful resources visually.</p><?php if($error): ?><div class="error"><?= e($error) ?></div><?php endif; ?><form method="post"><div class="field"><label>Username</label><input class="input" name="username" required></div><div class="field"><label>Email</label><input class="input" type="email" name="email" required></div><div class="field"><label>Password</label><input class="input" type="password" name="password" required></div><button class="btn" type="submit">Create account</button></form></div><?php require_once __DIR__.'/footer.php'; ?>